     5	/**
     6	 * Factory that wires element IDs to MudJsEvent instances.
     7	 * Provides connect/subscribe lifecycle entry points for .NET interop.
     8	 */
     9	class MudJsEventFactory {
    10	    /**
    11	     * Creates (or reuses) a JsEvent observer for the element and starts observing it.
    12	     */
    13	    connect(dotNetRef, elementId, options) {
    14	        //console.log('[MudBlazor | MudJsEventFactory] connect ', { dotNetRef, elementId, options });
    15	        if (!elementId)
    16	            throw "[MudBlazor | JsEvent] elementId: expected element id!";
    17	        const element = document.getElementById(elementId);
    18	        if (!element)
    19	            throw "[MudBlazor | JsEvent] no element found for id: " + elementId;
    20	        if (!element.mudJsEvent)
    21	            element.mudJsEvent = new MudJsEvent(dotNetRef, options);
    22	        element.mudJsEvent.connect(element);
    23	    }
    24	
    25	    /**
    26	     * Stops observing and detaches handlers for an element ID.
    27	     */
    28	    disconnect(elementId) {
    29	        const element = document.getElementById(elementId);
    30	        if (!element?.mudJsEvent)
    31	            return;
    32	        element.mudJsEvent.disconnect();
    33	    }
    34	
