    62	/**
    63	 * Observes a container and attaches configured event handlers to matching children.
    64	 * Keeps subscriptions stable across dynamic DOM changes from re-rendering.
    65	 */
    66	class MudJsEvent {
    67	    constructor(dotNetRef, options) {
    68	        this._dotNetRef = dotNetRef;
    69	        this._options = options || {};
    70	        this.logger = options.enableLogging ? console.log : () => { };
    71	        this.logger('[MudBlazor | JsEvent] Initialized', { options });
    72	        this._subscribedEvents = {};
    73	    }
    74	
    75	    /**
    76	     * Starts DOM observation for child nodes matching the configured target class.
    77	     */
    78	    connect(element) {
    79	        if (!this._options)
    80	            return;
    81	        if (!this._options.targetClass)
    82	            throw "_options.targetClass: css class name expected";
    83	        if (this._observer) {
    84	            // don't do double registration
    85	            return;
    86	        }
    87	        const targetClass = this._options.targetClass;
    88	        this.logger('[MudBlazor | JsEvent] Start observing DOM of element for changes to child with class ', { element, targetClass });
    89	        this._element = element;
    90	        this._observer = new MutationObserver(this.onDomChanged);
    91	        // MutationObserver callbacks do not preserve class context, so keep an explicit back-reference.
    92	        this._observer.mudJsEvent = this;
    93	        this._observer.observe(this._element, { attributes: false, childList: true, subtree: true });
    94	        this._observedChildren = [];
    95	    }
